import{c as t,S as h,j as i,m as a}from"./chunks/framework.8aa1YH_s.js";const u=JSON.parse('{"title":"Hồ sơ cá nhân (Giáo viên)","description":"","frontmatter":{},"headers":[],"relativePath":"giao-vien/ho-so-ca-nhan.md","filePath":"giao-vien/ho-so-ca-nhan.md","lastUpdated":0}'),o={name:"giao-vien/ho-so-ca-nhan.md"};function g(c,n,l,r,s,e){return h(),i("div",null,[...n[0]||(n[0]=[a('<h1 id="ho-so-ca-nhan-giao-vien" tabindex="-1">Hồ sơ cá nhân (Giáo viên) <a class="header-anchor" href="#ho-so-ca-nhan-giao-vien" aria-label="Permalink to “Hồ sơ cá nhân (Giáo viên)”">​</a></h1><p><strong>Đường dẫn:</strong> <code>https://lamsonedutech.vn/teacher/profile</code></p><p>Nơi quản lý thông tin tài khoản và các cài đặt cá nhân.</p><h2 id="cac-tab-chinh" tabindex="-1">Các tab chính <a class="header-anchor" href="#cac-tab-chinh" aria-label="Permalink to “Các tab chính”">​</a></h2><table tabindex="0"><thead><tr><th>Tab</th><th>Mục đích</th></tr></thead><tbody><tr><td><strong>Thông tin cá nhân</strong></td><td>Họ tên, SĐT, email, ngày sinh, giới tính, địa chỉ</td></tr><tr><td><strong>Hồ sơ giảng dạy</strong></td><td>Bio, ảnh đại diện, môn dạy, học vị, kinh nghiệm</td></tr><tr><td><strong>Đổi mật khẩu</strong></td><td>Thay mật khẩu định kỳ</td></tr><tr><td><strong>Thiết bị đăng nhập</strong></td><td>Xem các thiết bị đang sử dụng tài khoản</td></tr><tr><td><strong>Thông báo</strong></td><td>Cấu hình nhận email / push</td></tr></tbody></table><h2 id="thong-tin-ca-nhan" tabindex="-1">Thông tin cá nhân <a class="header-anchor" href="#thong-tin-ca-nhan" aria-label="Permalink to “Thông tin cá nhân”">​</a></h2><p>Sửa các trường:</p><ul><li>Họ và tên</li><li>Số điện thoại (cần xác thực OTP khi đổi)</li><li>Email (cần xác thực)</li><li>Ngày sinh</li><li>Giới tính</li><li>Địa chỉ</li><li>CMND / CCCD (nếu hệ thống có yêu cầu)</li></ul><p>Sau khi sửa → bấm <strong>Lưu</strong>.</p><h2 id="ho-so-giang-day-hien-thi-cong-khai" tabindex="-1">Hồ sơ giảng dạy (hiển thị công khai) <a class="header-anchor" href="#ho-so-giang-day-hien-thi-cong-khai" aria-label="Permalink to “Hồ sơ giảng dạy (hiển thị công khai)”">​</a></h2><p>Đây là phần học viên <strong>nhìn thấy</strong> ở trang khóa học của bạn. Hãy đầu tư thời gian làm tốt!</p><ul><li><strong>Ảnh đại diện</strong>: ảnh chân dung lịch sự, độ phân giải ≥ 400×400.</li><li><strong>Tên hiển thị</strong>: tên + chức danh (vd &quot;Thầy Nguyễn Văn A - Thạc sĩ Toán&quot;).</li><li><strong>Bio ngắn (1-2 câu)</strong>: hiển thị dưới ảnh.</li><li><strong>Giới thiệu chi tiết</strong> (rich text): kinh nghiệm, thành tích, lý do dạy, cam kết với học viên.</li><li><strong>Môn / Chuyên môn</strong>: chọn từ danh sách (Toán, Văn, Lý, Hóa, Sinh, Sử, Địa, Anh, ...).</li><li><strong>Học vị / Bằng cấp</strong>: Cử nhân / Thạc sĩ / Tiến sĩ.</li><li><strong>Kinh nghiệm</strong>: số năm giảng dạy.</li><li><strong>Ảnh / Video giới thiệu</strong> (tùy chọn).</li><li><strong>Mạng xã hội</strong> (tùy chọn): Facebook, YouTube channel, Zalo OA.</li></ul><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>Học viên thường so sánh giữa nhiều giáo viên trước khi đăng ký. Một hồ sơ đầy đủ ảnh + bio chỉn chu + video giới thiệu 1 phút có thể tăng tỷ lệ chuyển đổi đáng kể.</p></div><h2 id="đoi-mat-khau" tabindex="-1">Đổi mật khẩu <a class="header-anchor" href="#đoi-mat-khau" aria-label="Permalink to “Đổi mật khẩu”">​</a></h2><ol><li>Nhập <strong>Mật khẩu hiện tại</strong>.</li><li>Nhập <strong>Mật khẩu mới</strong> (≥ 8 ký tự, có chữ + số).</li><li>Nhập lại để xác nhận.</li><li>Bấm <strong>Đổi mật khẩu</strong>.</li></ol><blockquote><p>💡 Sau khi đổi, các thiết bị khác sẽ bị đăng xuất.</p></blockquote><h2 id="thiet-bi-đang-nhap" tabindex="-1">Thiết bị đăng nhập <a class="header-anchor" href="#thiet-bi-đang-nhap" aria-label="Permalink to “Thiết bị đăng nhập”">​</a></h2><p>Xem danh sách thiết bị đang sử dụng tài khoản:</p><ul><li>Trình duyệt, hệ điều hành.</li><li>Địa chỉ IP.</li><li>Thời gian đăng nhập gần nhất.</li></ul><p>Có nút <strong>Đăng xuất khỏi thiết bị này</strong> nếu phát hiện thiết bị lạ.</p><h2 id="thong-bao" tabindex="-1">Thông báo <a class="header-anchor" href="#thong-bao" aria-label="Permalink to “Thông báo”">​</a></h2><p>Bật / tắt:</p><ul><li>Email khi học viên đăng ký vào khóa.</li><li>Email khi có câu hỏi mới (Hỏi đáp).</li><li>Email khi có hóa đơn chiết khấu mới được cập nhật.</li><li>Push notification (nếu có app).</li></ul><h2 id="cau-hoi-thuong-gap" tabindex="-1">Câu hỏi thường gặp <a class="header-anchor" href="#cau-hoi-thuong-gap" aria-label="Permalink to “Câu hỏi thường gặp”">​</a></h2><p><strong>Đổi số điện thoại nhưng không nhận được OTP?</strong> → Kiểm tra hộp thư rác, chắc chắn nhập đúng số. Nếu vẫn không có, bấm <strong>Gửi lại</strong> sau 60s.</p><p><strong>Học viên báo &quot;không thấy thông tin giáo viên ở trang khóa&quot;?</strong> → Có thể bạn chưa lưu hồ sơ. Vào tab <strong>Hồ sơ giảng dạy</strong>, kiểm tra ảnh + bio, bấm <strong>Lưu</strong>.</p><p><strong>Quên mật khẩu mà không vào được tài khoản?</strong> → Liên hệ Admin để <strong>Reset mật khẩu</strong> giúp.</p>',27)])])}const p=t(o,[["render",g]]);export{u as __pageData,p as default};
